/* Tar faylınıñ muhtasını berilgen hedef yolğa çıqar.
Çıqaruv muvafaqiyetli olsa, true qaytar; aks holda, çıqaruv işlemi esnasında er angi bir hata (meselâ, fayl tapılmadı, ruhset hatası, bütün muhtanı çıqarıp olmağan) olsa, faqat false qaytar.

İpucu: Aşağıdaki kod, libarchive kitaphanesi ile tar faylınıñ muhtasını berilgen hedef yolğa nasıl çıqaruvını köster.

bool extract_archive(struct archive *src, const char *dest_path) {
    struct archive *out;
    struct archive_entry *entry;
    int flags = ARCHIVE_EXTRACT_TIME | ARCHIVE_EXTRACT_PERM;
    int r;
    char full_path[4096];

    // Arhiv yazıcısını başlat
    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);

    // Her bir kirisni oqu ve çıqar
    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // Tam yol yarat
        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);

        // Başlıq yaz
        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }

        // Malümatnı köçür
        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


